// _stateful.js — vanilla-JS counterpart to React useDisabledState.
// Mirrors the behavior of the inlined hook in button.tsx so the static-HTML
// output stays accessibility-equivalent to the React version (WCAG 2.1.1).
//
// Generated by /kit-add-html. Do not edit by hand — delete the file and
// re-run /kit-add-html to refresh. (/kit-update only manages the React
// pipeline's manifest; the HTML generator does not record this file there.)

/**
 * Wire aria-disabled handling onto an interactive element.
 *
 * The element stays focusable (keeps its tab stop), pointer events are
 * blocked via CSS (`pointer-events: none` on `[aria-disabled="true"]`), and
 * keyboard activation (Enter / Space) is short-circuited so screen-reader
 * users still hear the control exists but cannot trigger it.
 *
 * @param {HTMLElement} el
 * @param {{ onActivate?: (event: Event) => void }} [opts]
 * @returns {{ setDisabled: (next: boolean) => void, destroy: () => void }}
 */
export function wireDisabled(el, opts = {}) {
  if (!(el instanceof HTMLElement)) {
    throw new TypeError('wireDisabled: expected an HTMLElement');
  }

  const isDisabled = () => el.getAttribute('aria-disabled') === 'true';

  // Native <button> fires a synthetic click after Enter/Space keydown — so
  // without coordination both handlers would invoke onActivate twice. We
  // mark a one-shot suppression flag in keydown that the click handler
  // honours and then clears.
  let suppressNextClick = false;

  const onClick = (event) => {
    if (suppressNextClick) {
      suppressNextClick = false;
      return;
    }
    if (isDisabled()) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    opts.onActivate?.(event);
  };

  const onKeydown = (event) => {
    if (event.key !== 'Enter' && event.key !== ' ') return;
    if (isDisabled()) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    if (el.tagName === 'BUTTON') {
      // Let the browser's synthetic click do the work; suppress the duplicate
      // call we'd otherwise make from this handler.
      suppressNextClick = true;
      return;
    }
    event.preventDefault();
    opts.onActivate?.(event);
  };

  el.addEventListener('click', onClick);
  el.addEventListener('keydown', onKeydown);

  return {
    setDisabled(next) {
      el.setAttribute('aria-disabled', next ? 'true' : 'false');
      el.classList.toggle('is-disabled', Boolean(next));
    },
    destroy() {
      el.removeEventListener('click', onClick);
      el.removeEventListener('keydown', onKeydown);
    },
  };
}

/**
 * Convenience: wire every element matching a selector in `root`.
 *
 * @param {string} selector
 * @param {ParentNode} [root=document]
 * @returns {Array<ReturnType<typeof wireDisabled>>}
 */
export function wireDisabledAll(selector, root = document) {
  return Array.from(root.querySelectorAll(selector)).map((el) =>
    wireDisabled(el),
  );
}
